53	
54	            // セルが無ければ評価も表示も不要
55	            // Nothing to evaluate or show without cells
56	            if (placeInfos.Count == 0) { Hide(); return true; }
57	
58	            InvalidateCacheOnKeyChange();
59	
60	            // セル順に仮想在庫を減算しながら評価し、サーバーの逐次設置と同じ消費結果を予測する
61	            // Evaluate cells in order while decrementing a virtual inventory, predicting the server's sequential consumption
62	            // 注意: ドラッグ中の未設置電柱同士の接続は評価に現れない近似（サーバーが設置順に個別再検証するため安全側）
63	            // Note: connections between not-yet-placed poles in a drag are approximated away (the server re-validates each in placement order, so this stays safe)
64	            var virtualCounts = BuildVirtualCounts();
65	            var placingItemId = MasterHolder.BlockMaster.GetItemId(blockId);
66	            var totalCost = 0;
67	            var anyPlaceable = false;
