86	            cursorInfo ??= placeInfos[^1];
87	            var cursorTargets = cursorInfo.Placeable ? ResolveTargetPositions(cursorInfo.Position) : EmptyTargets;
88	            _renderer.Show(cursorInfo.Position, cursorTargets, totalCost);
89	
90	            // 設置可能なセルが1つでも残っていればクリック許可（不可セルはサーバーが個別に拒否する既存方針に揃える）
91	            // Allow the click when any cell remains placeable (bad cells are rejected per-cell by the server, matching existing policy)
92	            return anyPlaceable;
93	
94	            #region Internal
95	
96	            void InvalidateCacheOnKeyChange()
97	            {
98	                if (_hasCacheKey && _cachedDirection == direction && _cachedBlockId == blockId) return;
99	                _cellGeometryCache.Clear();
100	                _cachedDirection = direction;
101	                _cachedBlockId = blockId;
102	                _hasCacheKey = true;
103	            }
104	
105	            Dictionary<ItemId, int> BuildVirtualCounts()
106	            {
107	                // 所持アイテムをID別に合算する
108	                // Sum held items per item id
109	                var counts = new Dictionary<ItemId, int>();
110	                foreach (var itemStack in inventory)
111	                {
112	                    if (itemStack.Count <= 0) continue;
113	                    counts[itemStack.Id] = counts.GetValueOrDefault(itemStack.Id) + itemStack.Count;
114	                }
115	
116	                return counts;
