160	            var wireItems = MasterHolder.BlockMaster.Blocks.ElectricWireItems;
161	            if (wireItems.Length == 0) return true;
162	
163	            foreach (var wireItem in wireItems)
164	            {
165	                var candidateItemId = MasterHolder.ItemMaster.GetItemId(wireItem.ItemGuid);
166	                if (!TrySumCost(candidateItemId, out var cost)) continue;
167	
168	                // 設置ブロックと電線が同一アイテムなら設置分の1個を上乗せして判定する
169	                // Require one extra when the placed block shares the wire item
170	                var required = cost + (candidateItemId == placingItemId ? 1 : 0);
171	                if (virtualCounts.GetValueOrDefault(candidateItemId) < required) continue;
172	
173	                wireItemId = candidateItemId;
174	                totalCost = cost;
175	                return true;
176	            }
177	
178	            return false;
179	
180	            #region Internal
181	
182	            bool TrySumCost(ItemId candidateItemId, out int cost)
183	            {
184	                cost = 0;
185	                foreach (var target in targets)
186	                {
187	                    if (!ElectricWirePlacementEvaluator.TryCalculateWireCost(candidateItemId, target.Distance, out var targetCost)) return false;
188	                    cost += targetCost.Count;
189	                }
190	
191	                return true;
192	            }
193	
194	            #endregion
195	        }
