1	using System;
2	using System.Collections.Generic;
3	using Core.Item.Interface;
4	using Core.Master;
5	using Game.Block.Interface;
6	using Game.Block.Interface.Extension;
7	using Game.Context;
8	using Game.EnergySystem;
9	using Core.Inventory;
10	using Mooresmaster.Model.BlocksModule;
11	using UnityEngine;
12	
13	namespace Server.Protocol.PacketResponse.Util.ElectricWire
14	{
15	    /// <summary>
16	    /// 設置時の電力ワイヤー自動接続を計画・実行する
17	    /// Plans and executes wire auto-connect on placement
18	    /// </summary>
19	    public static class ElectricWireAutoConnectService
20	    {
21	        public static ElectricWireAutoConnectPlan EvaluateAutoConnect(BlockId blockId, Vector3Int position, BlockDirection direction, IReadOnlyList<(ItemId itemId, int count)> reservedItems, IReadOnlyList<IItemStack> inventoryItems)
22	        {
23	            // 電線アイテム未設定のマスタでは自動接続なしで設置を許可する
24	            // With no wire items configured, allow placement without auto-connect
25	            if (MasterHolder.BlockMaster.Blocks.ElectricWireItems.Length == 0)
26	                return ElectricWireAutoConnectPlan.Success(Array.Empty<(BlockInstanceId, ElectricWireConnectionCost)>(), ItemMaster.EmptyItemId);
27	
28	            var blockMaster = MasterHolder.BlockMaster.GetBlockMaster(blockId);
29	
30	            // 電柱設置か機械/発電機設置かで対象選定ロジックが異なる
31	            // Target selection differs between pole placement and machine/generator placement
32	            var candidates = blockMaster.BlockParam is ElectricPoleBlockParam poleParam
33	                ? ElectricWireAutoConnectTargetCollector.CollectPoleTargets(poleParam, position)
34	                : CollectMachineTargets(blockMaster, position, direction);
35	
36	            if (candidates.Count == 0)
37	                return ElectricWireAutoConnectPlan.Success(Array.Empty<(BlockInstanceId, ElectricWireConnectionCost)>(), ItemMaster.EmptyItemId);
38	
39	            // 合計コストを所持数が満たす最初の電線を選ぶ
40	            // Pick the first wire item whose held count covers the summed cost across all targets
41	            return TrySelectWireItem(out var targets, out var wireItemId)
42	                ? ElectricWireAutoConnectPlan.Success(targets, wireItemId)
43	                : ElectricWireAutoConnectPlan.Failure(ElectricWirePlacementFailureReason.NoWireItem);
44	
45	            #region Internal
46	
47	            List<(BlockInstanceId TargetId, IElectricWireConnector Connector, float Distance)> CollectMachineTargets(BlockMasterElement master, Vector3Int pos, BlockDirection dir)
48	            {
49	                // 自身の接続容量が0なら探索するまでもなく対象なし
50	                // No point searching when this block has zero connection capacity
51	                if (!ElectricWireBlockParamResolver.TryGetWireParam(master.BlockParam, out var ownCapacity, out var ownMaxWireLength) || ownCapacity <= 0)
52	                    return new List<(BlockInstanceId, IElectricWireConnector, float)>();
53	
54	                return ElectricWireAutoConnectTargetCollector.CollectMachineTargets(master, pos, dir, ownMaxWireLength);
55	            }
56	
57	            // 距離を満たす電線をマスタ設定順に探す
58	            // Search wire item configs in master order for one covering all target distances
59	            bool TrySelectWireItem(out List<(BlockInstanceId, ElectricWireConnectionCost)> selectedTargets, out ItemId selectedWireItemId)
60	            {
61	                foreach (var electricWireItem in MasterHolder.BlockMaster.Blocks.ElectricWireItems)
62	                {
63	                    var candidateItemId = MasterHolder.ItemMaster.GetItemId(electricWireItem.ItemGuid);
64	                    if (!TryBuildTargets(candidateItemId, out var builtTargets, out var totalRequired)) continue;
65	
66	                    // 建設コスト等で予約済みの数量を上乗せして所持数を判定する
67	                    // Add quantities reserved by construction costs when judging held counts
68	                    var reservedCount = 0;
69	                    foreach (var reserved in reservedItems)
70	                    {
71	                        if (reserved.itemId == candidateItemId) reservedCount += reserved.count;
72	                    }
73	                    var requiredTotal = totalRequired + reservedCount;
74	                    if (!HasEnoughItem(candidateItemId, requiredTotal)) continue;
75	
76	                    selectedTargets = builtTargets;
77	                    selectedWireItemId = candidateItemId;
78	                    return true;
79	                }
80	
81	                selectedTargets = null;
82	                selectedWireItemId = ItemMaster.EmptyItemId;
83	                return false;
84	            }
85	
86	            bool TryBuildTargets(ItemId candidateItemId, out List<(BlockInstanceId, ElectricWireConnectionCost)> builtTargets, out int totalRequired)
87	            {
88	                builtTargets = new List<(BlockInstanceId, ElectricWireConnectionCost)>();
89	                totalRequired = 0;
90	
91	                foreach (var candidate in candidates)
92	                {
93	                    if (!ElectricWirePlacementEvaluator.TryCalculateWireCost(candidateItemId, candidate.Distance, out var cost))
94	                    {
95	                        builtTargets = null;
96	                        return false;
97	                    }
98	
99	                    builtTargets.Add((candidate.TargetId, cost));
100	                    totalRequired += cost.Count;
101	                }
102	
