1	using System.Collections.Generic;
2	using Core.Inventory;
3	using Core.Item.Interface;
4	using Core.Master;
5	using Game.Block.Event;
6	using Game.Block.Interface;
7	using Game.Block.Interface.Event;
8	using Game.Context;
9	using Game.Fluid;
10	using Game.UnlockState;
11	using Mooresmaster.Model.MachineRecipesModule;
12	
13	namespace Game.Block.Blocks.Machine.Inventory
14	{
15	    /// <summary>
16	    ///     インプットのインベントリとアウトプットのインベントリを同じように扱う
17	    ///     Insertなどの処理は基本的にInputのインベントリにのみ行う
18	    /// </summary>
19	    public class VanillaMachineInputInventory : IVanillaMachineSubInventory
20	    {
21	        public IReadOnlyList<IItemStack> InputSlot => _itemDataStoreService.InventoryItems;
22	        IReadOnlyList<IItemStack> IVanillaMachineSubInventory.Items => InputSlot;
23	        public IReadOnlyList<FluidContainer> FluidInputSlot => _fluidContainers;
24	        
25	        private readonly BlockId _blockId;
26	        private readonly BlockInstanceId _blockInstanceId;
27	        
28	        private readonly BlockOpenableInventoryUpdateEvent _blockInventoryUpdate;
29	        private readonly FluidContainer[] _fluidContainers;
30	        private readonly IGameUnlockStateData _gameUnlockStateData;
31	        private readonly OpenableInventoryItemDataStoreService _itemDataStoreService;
32	        
33	        public VanillaMachineInputInventory(
34	            BlockId blockId,
35	            int inputSlot,
36	            int innerTankCount,
37	            float innerTankCapacity,
38	            BlockOpenableInventoryUpdateEvent blockInventoryUpdate,
39	            BlockInstanceId blockInstanceId,
40	            IGameUnlockStateData gameUnlockStateData)
41	        {
42	            _blockId = blockId;
43	            _blockInventoryUpdate = blockInventoryUpdate;
44	            _blockInstanceId = blockInstanceId;
45	            _gameUnlockStateData = gameUnlockStateData;
46	            
47	            var option = new OpenableInventoryItemDataStoreServiceOption()
48	            {
49	                AllowMultipleStacksPerItemOnInsert = false,
50	            };
51	            _itemDataStoreService = new OpenableInventoryItemDataStoreService(InvokeEvent, ServerContext.ItemStackFactory, inputSlot, option);
52	            
53	            _fluidContainers = new FluidContainer[innerTankCount];
54	            for (var i = 0; i < innerTankCount; i++)
55	            {
56	                _fluidContainers[i] = new FluidContainer(innerTankCapacity);
57	            }
58	        }
59	        
60	        public bool IsAllowedToStartProcess()
61	        {
62	            //ブロックIDと現在のインプットスロットからレシピを検索する
63	            if (TryGetRecipeElement(out var recipe))
64	            {
65	                //実行できるレシピかどうか
66	                return recipe.RecipeConfirmation(_blockId, InputSlot, FluidInputSlot);
67	            }
68	            return false;
69	        }
70	        
71	        public IItemStack InsertItem(IItemStack itemStack)
72	        {
73	            return _itemDataStoreService.InsertItem(itemStack);
74	        }
75	        
76	        public List<IItemStack> InsertItem(List<IItemStack> itemStacks)
77	        {
78	            return _itemDataStoreService.InsertItem(itemStacks);
79	        }
80	        
81	        public bool TryGetRecipeElement(out MachineRecipeMasterElement recipe)
82	        {
83	            if (!MachineRecipeMasterUtil.TryGetRecipeElement(_blockId, InputSlot, FluidInputSlot, out recipe)) return false;
84	
85	            // アンロックされていないレシピは機械で使用不可にする
86	            // Locked recipes cannot be used by machines
87	            if (!_gameUnlockStateData.MachineRecipeUnlockStateInfos.TryGetValue(recipe.MachineRecipeGuid, out var unlockInfo))
88	            {
89	                recipe = null;
90	                return false;
91	            }
92	            if (unlockInfo.IsUnlocked) return true;
93	
94	            recipe = null;
95	            return false;
96	        }
97	        
98	        public void ReduceInputSlot(MachineRecipeMasterElement recipe)
99	        {
100	            //inputスロットからアイテムを減らす
101	            foreach (var item in recipe.InputItems)
102	            {
103	                if (item.IsRemain.HasValue && item.IsRemain.Value) continue;
104	                
105	                for (var i = 0; i < InputSlot.Count; i++)
106	                {
107	                    var itemId = MasterHolder.ItemMaster.GetItemId(item.ItemGuid);
108	                    
109	                    if (_itemDataStoreService.InventoryItems[i].Id != itemId || item.Count > InputSlot[i].Count) continue;
110	                    //アイテムを減らす
111	                    _itemDataStoreService.SetItem(i, InputSlot[i].SubItem(item.Count));
112	                    break;
113	                }
114	            }
115	            
116	            //inputスロットから液体を減らす
117	            foreach (var inputFluid in recipe.InputFluids)
118	            {
119	                var fluidId = MasterHolder.FluidMaster.GetFluidId(inputFluid.FluidGuid);
120	                
121	                // 任意のスロットから必要な液体を減らす
122	                for (var i = 0; i < _fluidContainers.Length; i++)
123	                {
124	                    if (_fluidContainers[i].FluidId == fluidId && _fluidContainers[i].Amount >= inputFluid.Amount)
125	                    {
126	                        _fluidContainers[i].Amount -= inputFluid.Amount;
